WHERE p.PRD_USE_YN = 'Y' AND p.PRD_STATUS_CD = 'PRDC0002' AND a.AUC_STATUS_CD != 'AUCC0005'
AND ( p.PRD_NM LIKE CONCAT('%', #{condition.keyword}, '%') OR c.CAT_NM LIKE CONCAT('%', #{condition.keyword}, '%') OR u.USR_NM LIKE CONCAT('%', #{condition.keyword}, '%') )
AND c.CAT_NM IN
#{category}
AND a.AUC_CUR_AMT >= #{condition.minPrice}
AND a.AUC_CUR_AMT <= #{condition.maxPrice}
AND p.PRD_IBY_AMT IS NOT NULL AND p.PRD_IBY_AMT > 0
AND p.PRD_TRD_METHOD_CD = #{condition.tradeMethodCode}
AND ( 1 = 0
OR a.AUC_STATUS_CD = 'AUCC0001'
OR a.AUC_STATUS_CD = 'AUCC0002'
OR ( a.AUC_STATUS_CD = 'AUCC0002' AND a.AUC_END_DT BETWEEN NOW() AND DATE_ADD(NOW(), INTERVAL 24 HOUR) )
)
AND a.AUC_STATUS_CD IN ('AUCC0001', 'AUCC0002')
